using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchString_NoMatch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsSortedStudents()
        {
            // Add another student for sort testing
            _context.Students.Add(new Student
            {
                FirstMidName = "Zack",
                LastName = "Zebra",
                EnrollmentDate = DateTime.Parse("2012-01-01")
            });
            _context.SaveChanges();

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Equal("Zebra", model.First().LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsSortedStudents()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsSortedStudents()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Details_WithValidId_ReturnsStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_EnrollmentDateOutOfRange_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1700, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();
            // Detach entity so we can update it
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            student.FirstMidName = "Updated";

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = _context.Students.First();
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();

            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Students);
        }
    }
}

