    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_SecondPage_HasPreviousPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.True(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_NoNextPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.True(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            using var context = TestHelper.CreateContext();
            var source = context.Students.OrderBy(s => s.LastName);

            var result = PaginatedList<Student>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
        }
    }
}

