using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_WithValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 3000, Title = "", Credits = 3 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_WithValidImage_UploadsFile()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 3000,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFormFile("test.jpg", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(3000);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsView()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 3001,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsView()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 3002,
                Title = "Big Image",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = _context.Courses.First();

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
        {
            var course = _context.Courses.First();

            var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Courses);
        }

        private Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var fileMock = new Mock<IFormFile>();
            var ms = new MemoryStream(new byte[length]);
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return fileMock;
        }
    }
}

