using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_WithValidId_ReturnsDepartment()
        {
            var dept = _context.Departments.First();

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = _context.Instructors.First().ID
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsDepartment()
        {
            var dept = _context.Departments.First();

            var result = _controller.Edit(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            dept.Name = "Updated Engineering";

            var result = _controller.Edit(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.First();

            var result = _controller.Edit(dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsDepartment()
        {
            var dept = _context.Departments.First();

            var result = _controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.First();

            var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Departments);
        }
    }
}

