using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanCreateInMemory()
        {
            using var context = TestHelper.CreateContext();

            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateContext();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };
            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();

            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("User", retrieved.LastName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestHelper.CreateContext();
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000,
                StartDate = DateTime.Now
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 5000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.Find(5000);

            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved.Title);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(context);

            var ca = context.CourseAssignments.First();

            Assert.NotEqual(0, ca.CourseID);
            Assert.NotEqual(0, ca.InstructorID);
        }

        [Fact]
        public void SchoolContext_Enrollment_Relationship()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(context);

            var enrollment = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }

        [Fact]
        public void SchoolContext_Department_WithAdministrator()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(context);

            var dept = context.Departments
                .Include(d => d.Administrator)
                .First();

            Assert.NotNull(dept.Administrator);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsDatabase()
        {
            using var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
        }

        [Fact]
        public void Initialize_CalledTwice_DoesNotDuplicate()
        {
            using var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);
            var countBefore = context.Students.Count();
            DbInitializer.Initialize(context);
            var countAfter = context.Students.Count();

            Assert.Equal(countBefore, countAfter);
        }
    }

    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_SecondPage_HasPreviousPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.True(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_NoNextPage()
        {
            using var context = TestHelper.CreateContext();
            for (int i = 0; i < 25; i++)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            context.SaveChanges();

            var source = context.Students.OrderBy(s => s.LastName);
            var result = PaginatedList<Student>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.True(result.HasPreviousPage);
